// apps/api/src/routes/communities.ts
async function registerCommunityRoutes(app) {
  app.get("/communities", async (req) => {
    const { q } = req.query;
    const communities = await prisma.community.findMany({
      where: q ? { OR: [{ name: { contains: q, mode: "insensitive" } }, { description: { contains: q, mode: "insensitive" } }] } : {},
      orderBy: { memberCount: "desc" },
      take: 30,
      include: { creator: { select: { handle: true, name: true, avatarUrl: true } } }
    });
    return { items: communities };
  });
  app.get("/communities/:slug", async (req, reply) => {
    const { slug } = req.params;
    const community = await prisma.community.findUnique({
      where: { slug },
      include: {
        creator: { select: { handle: true, name: true, avatarUrl: true } },
        members: { include: { user: { select: { handle: true, name: true, avatarUrl: true, verified: true } } }, take: 20 }
      }
    });
    if (!community) return reply.code(404).send({ error: "Topluluk bulunamad\u0131" });
    return community;
  });
  app.post("/communities", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { name, description, imageUrl: imageUrl2, private: isPrivate } = req.body;
    if (!name?.trim()) return reply.code(400).send({ error: "\u0130sim gerekli" });
    const check = moderate(name + " " + (description ?? ""));
    if (!check.ok) return reply.code(422).send({ error: check.message });
    const slug = name.toLowerCase().replace(/[^a-z0-9ğüşıöçğüşıöç]/gi, "-").replace(/-+/g, "-").slice(0, 50) + "-" + Math.random().toString(36).slice(2, 6);
    const community = await prisma.community.create({
      data: {
        name: name.trim(),
        slug,
        description: description?.trim(),
        imageUrl: imageUrl2,
        private: isPrivate ?? false,
        creatorId: userId,
        memberCount: 1
      }
    });
    await prisma.communityMember.create({
      data: { userId, communityId: community.id, role: "admin" }
    });
    return reply.code(201).send(community);
  });
  app.post("/communities/:slug/join", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { slug } = req.params;
    const community = await prisma.community.findUnique({ where: { slug } });
    if (!community) return reply.code(404).send({ error: "Topluluk bulunamad\u0131" });
    const existing = await prisma.communityMember.findUnique({
      where: { userId_communityId: { userId, communityId: community.id } }
    });
    if (existing) {
      await prisma.communityMember.delete({ where: { userId_communityId: { userId, communityId: community.id } } });
      await prisma.community.update({ where: { id: community.id }, data: { memberCount: { decrement: 1 } } });
      return { joined: false };
    }
    await prisma.communityMember.create({ data: { userId, communityId: community.id } });
    await prisma.community.update({ where: { id: community.id }, data: { memberCount: { increment: 1 } } });
    return { joined: true };
  });
  app.get("/communities/my/list", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const memberships = await prisma.communityMember.findMany({
      where: { userId },
      include: { community: { include: { creator: { select: { handle: true, name: true, avatarUrl: true } } } } },
      orderBy: { joinedAt: "desc" }
    });
    return { items: memberships.map((m) => m.community) };
  });
  app.get("/communities/featured", async () => {
    const communities = await prisma.community.findMany({
      where: { private: false },
      orderBy: { memberCount: "desc" },
      take: 6,
      include: { creator: { select: { handle: true, name: true, avatarUrl: true, verified: true } } }
    });
    return { items: communities };
  });
  app.get("/communities/trending", async () => {
    const dayAgo = new Date(Date.now() - 864e5);
    const recentJoins = await prisma.communityMember.groupBy({
      by: ["communityId"],
      where: { joinedAt: { gte: dayAgo } },
      _count: { communityId: true },
      orderBy: { _count: { communityId: "desc" } },
      take: 10
    });
    const ids = recentJoins.map((r) => r.communityId);
    if (ids.length === 0) {
      const fallback = await prisma.community.findMany({
        where: { private: false },
        orderBy: { memberCount: "desc" },
        take: 10,
        include: { creator: { select: { handle: true, name: true, avatarUrl: true } } }
      });
      return { items: fallback, period: "alltime" };
    }
    const communities = await prisma.community.findMany({
      where: { id: { in: ids } },
      include: { creator: { select: { handle: true, name: true, avatarUrl: true } } }
    });
    const ordered = recentJoins.map((r) => ({
      ...communities.find((c) => c.id === r.communityId),
      newMembersToday: r._count.communityId
    })).filter(Boolean);
    return { items: ordered, period: "24h" };
  });
  app.get("/communities/:slug/posts", async (req, reply) => {
    const { slug } = req.params;
    const { limit = "20", cursor } = req.query;
    const take = Math.min(Number(limit), 50);
    const community = await prisma.community.findUnique({ where: { slug } });
    if (!community) return reply.code(404).send({ error: "Topluluk bulunamad\u0131" });
    const memberIds = (await prisma.communityMember.findMany({
      where: { communityId: community.id },
      select: { userId: true },
      take: 200
    })).map((m) => m.userId);
    const posts = await prisma.post.findMany({
      where: {
        authorId: { in: memberIds },
        ...cursor ? { createdAt: { lt: new Date(cursor) } } : {}
      },
      take,
      orderBy: { createdAt: "desc" },
      include: {
        author: { select: { handle: true, name: true, avatarUrl: true, verified: true } }
      }
    });
    return {
      posts,
      nextCursor: posts.length === take ? posts[posts.length - 1].createdAt.toISOString() : null
    };
  });
  app.get("/communities/:slug/stats", async (req, reply) => {
    const { slug } = req.params;
    const community = await prisma.community.findUnique({ where: { slug } });
    if (!community) return reply.code(404).send({ error: "Topluluk bulunamad\u0131" });
    const weekAgo = new Date(Date.now() - 7 * 864e5);
    const newMembersWeek = await prisma.communityMember.count({
      where: { communityId: community.id, joinedAt: { gte: weekAgo } }
    });
    return {
      memberCount: community.memberCount,
      newMembersThisWeek: newMembersWeek,
      growthRate: community.memberCount > 0 ? Math.round(newMembersWeek / community.memberCount * 100 * 10) / 10 : 0
    };
  });
  app.get("/communities/:slug/members", async (req, reply) => {
    const { slug } = req.params;
    const { limit = "20" } = req.query;
    const community = await prisma.community.findUnique({ where: { slug } });
    if (!community) return reply.code(404).send({ error: "Topluluk bulunamad\u0131" });
    const members = await prisma.communityMember.findMany({
      where: { communityId: community.id },
      take: Math.min(Number(limit), 100),
      orderBy: { joinedAt: "asc" },
      include: { user: { select: { handle: true, name: true, avatarUrl: true, verified: true } } }
    });
    return { members: members.map((m) => ({ ...m.user, role: m.role, joinedAt: m.joinedAt })) };
  });
}

// apps/api/src/routes/subscriptions.ts
async function registerSubscriptionRoutes(app) {
  app.post("/subscriptions/plan", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    return { ok: true, message: "Plan ayarland\u0131" };
  });
  app.post("/subscriptions/subscribe", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { creatorId, pricePart, currency = "PART", txHash, durationDays = 30 } = req.body;
    if (!creatorId || !pricePart) return reply.code(400).send({ error: "creatorId ve pricePart gerekli" });
    if (creatorId === userId) return reply.code(400).send({ error: "Kendinize abone olamazs\u0131n\u0131z" });
    const expiresAt = new Date(Date.now() + durationDays * 864e5);
    const sub = await prisma.subscription.upsert({
      where: { subscriberId_creatorId: { subscriberId: userId, creatorId } },
      update: { pricePart: String(pricePart), currency, txHash, expiresAt, active: true },
      create: { subscriberId: userId, creatorId, pricePart: String(pricePart), currency, txHash, expiresAt }
    });
    await prisma.user.update({
      where: { id: creatorId },
      data: { earningsPart: { increment: pricePart } }
    });
    await addXp(userId, 30);
    await addXp(creatorId, 50);
    return reply.code(201).send(sub);
  });
  app.get("/subscriptions/my", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const subs = await prisma.subscription.findMany({
      where: { subscriberId: userId, active: true },
      include: { creator: { select: { handle: true, name: true, avatarUrl: true, verified: true } } },
      orderBy: { createdAt: "desc" }
    });
    return { items: subs };
  });
  app.get("/subscriptions/subscribers", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const subs = await prisma.subscription.findMany({
      where: { creatorId: userId, active: true },
      include: { subscriber: { select: { handle: true, name: true, avatarUrl: true } } },
      orderBy: { createdAt: "desc" }
    });
    const total = subs.reduce((acc, s) => acc + Number(s.pricePart), 0);
    return { items: subs, totalEarned: total, count: subs.length };
  });
  app.get("/subscriptions/check/:creatorId", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { creatorId } = req.params;
    const sub = await prisma.subscription.findUnique({
      where: { subscriberId_creatorId: { subscriberId: userId, creatorId } }
    });
    const active = sub?.active && sub.expiresAt > /* @__PURE__ */ new Date();
    return { subscribed: !!active, expiresAt: sub?.expiresAt };
  });
}

// apps/api/src/routes/events.ts
async function registerEventRoutes(app) {
  app.get("/events", async (req) => {
    const { upcoming } = req.query;
    const now = /* @__PURE__ */ new Date();
    const events = await prisma.event.findMany({
      where: upcoming ? { startAt: { gte: now } } : {},
      orderBy: { startAt: "asc" },
      take: 30,
      include: {
        organizer: { select: { handle: true, name: true, avatarUrl: true } },
        _count: { select: { attendees: true } }
      }
    });
    return { items: events };
  });
  app.post("/events", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { title, description, imageUrl: imageUrl2, startAt, endAt, location, online, maxAttendees, pricePart } = req.body;
    if (!title || !startAt) return reply.code(400).send({ error: "Ba\u015Fl\u0131k ve ba\u015Flang\u0131\xE7 tarihi gerekli" });
    const event = await prisma.event.create({
      data: {
        organizerId: userId,
        title: title.trim(),
        description,
        imageUrl: imageUrl2,
        startAt: new Date(startAt),
        endAt: endAt ? new Date(endAt) : null,
        location,
        online: online ?? true,
        maxAttendees: maxAttendees ? Number(maxAttendees) : null,
        pricePart: String(pricePart ?? 0)
      }
    });
    await prisma.eventAttendee.create({ data: { userId, eventId: event.id, status: "organizer" } });
    return reply.code(201).send(event);
  });
  app.post("/events/:id/attend", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { id } = req.params;
    const event = await prisma.event.findUnique({ where: { id }, include: { _count: { select: { attendees: true } } } });
    if (!event) return reply.code(404).send({ error: "Etkinlik bulunamad\u0131" });
    if (event.maxAttendees && event._count.attendees >= event.maxAttendees)
      return reply.code(409).send({ error: "Etkinlik dolu" });
    const existing = await prisma.eventAttendee.findUnique({ where: { userId_eventId: { userId, eventId: id } } });
    if (existing) {
      await prisma.eventAttendee.delete({ where: { userId_eventId: { userId, eventId: id } } });
      return { attending: false };
    }
    await prisma.eventAttendee.create({ data: { userId, eventId: id } });
    return { attending: true };
  });
  app.get("/events/my", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const attending = await prisma.eventAttendee.findMany({
      where: { userId },
      include: { event: { include: { organizer: { select: { handle: true, name: true, avatarUrl: true } } } } },
      orderBy: { event: { startAt: "asc" } }
    });
    return { items: attending.map((a) => a.event) };
  });
}

