var TREASURY2 = (process.env.TREASURY_ADDRESS ?? process.env.NEXT_PUBLIC_TREASURY_ADDRESS ?? "").toLowerCase();
async function isOwner(req, reply) {
  const userId = requireAuth(req, reply);
  if (!userId) return false;
  if (!TREASURY2) {
    reply.code(403).send({ error: "Treasury tan\u0131ml\u0131 de\u011Fil" });
    return false;
  }
  const user = await prisma.user.findUnique({ where: { id: userId }, select: { walletAddress: true } });
  if (user?.walletAddress?.toLowerCase() !== TREASURY2) {
    reply.code(403).send({ error: "Bu panel yaln\u0131zca platform sahibine a\xE7\u0131kt\u0131r" });
    return false;
  }
  return true;
}
var blockedIPs = /* @__PURE__ */ new Set();
var warnedUsers = /* @__PURE__ */ new Map();
async function registerSentinelRoutes(app) {
  app.get("/admin/sentinel/report", async (req, reply) => {
    if (!await isOwner(req, reply)) return;
    const cached2 = getLastReport();
    if (cached2) return cached2;
    return await generateReport();
  });
  app.post("/admin/sentinel/scan", async (req, reply) => {
    if (!await isOwner(req, reply)) return;
    return await generateReport();
  });
  app.post("/admin/sentinel/action", async (req, reply) => {
    if (!await isOwner(req, reply)) return;
    const { action, target } = req.body;
    if (!action || !target) return reply.code(400).send({ error: "action ve target zorunlu" });
    switch (action) {
      case "block_ip": {
        blockedIPs.add(target);
        recordSecurityEvent("ip_blocked", `IP manuel olarak engellendi: ${target}`);
        return { ok: true, msg: `${target} engellendi` };
      }
      case "unblock_ip": {
        blockedIPs.delete(target);
        return { ok: true, msg: `${target} engel kald\u0131r\u0131ld\u0131` };
      }
      case "warn_user": {
        warnedUsers.set(target, { reason: "Platform kurallar\u0131n\u0131 ihlal", at: Date.now() });
        await prisma.notification.create({
          data: {
            userId: target,
            kind: "system",
            text: "Hesab\u0131n\u0131z platform kurallar\u0131n\u0131 ihlal etti\u011Fi i\xE7in uyar\u0131ld\u0131."
          }
        }).catch(() => {
        });
        return { ok: true, msg: `Kullan\u0131c\u0131 uyar\u0131ld\u0131: ${target}` };
      }
      case "suspend_user": {
        await prisma.user.update({
          where: { id: target },
          data: { isPrivate: true }
        }).catch(() => {
        });
        return { ok: true, msg: `Kullan\u0131c\u0131 ask\u0131ya al\u0131nd\u0131: ${target}` };
      }
      case "delete_post": {
        await prisma.post.delete({ where: { id: target } }).catch(() => {
        });
        return { ok: true, msg: `G\xF6nderi silindi: ${target}` };
      }
      case "end_campaign": {
        await prisma.campaign.update({ where: { id: target }, data: { status: "ended" } }).catch(() => {
        });
        return { ok: true, msg: `Kampanya sonland\u0131r\u0131ld\u0131: ${target}` };
      }
      default:
        return reply.code(400).send({ error: `Bilinmeyen eylem: ${action}` });
    }
  });
  app.get("/admin/sentinel/blocked-ips", async (req, reply) => {
    if (!await isOwner(req, reply)) return;
    return { ips: [...blockedIPs] };
  });
  app.get("/admin/sentinel/warned-users", async (req, reply) => {
    if (!await isOwner(req, reply)) return;
    const entries = [...warnedUsers.entries()].map(([id, v]) => ({ id, ...v }));
    return { users: entries };
  });
  app.get("/admin/sentinel/stats", async (req, reply) => {
    if (!await isOwner(req, reply)) return;
    const [
      totalUsers,
      totalPosts,
      totalReels,
      totalCampaigns,
      activeCampaigns,
      totalTips,
      totalMessages
    ] = await Promise.all([
      prisma.user.count(),
      prisma.post.count(),
      prisma.reel.count(),
      prisma.campaign.count(),
      prisma.campaign.count({ where: { status: "active" } }),
      prisma.tip.count(),
      prisma.message.count()
    ]);
    const dayAgo = new Date(Date.now() - 864e5);
    const [newUsers24h, newPosts24h] = await Promise.all([
      prisma.user.count({ where: { createdAt: { gte: dayAgo } } }),
      prisma.post.count({ where: { createdAt: { gte: dayAgo } } })
    ]);
    return {
      totalUsers,
      totalPosts,
      totalReels,
      totalCampaigns,
      activeCampaigns,
      totalTips,
      totalMessages,
      newUsers24h,
      newPosts24h,
      blockedIPs: blockedIPs.size
    };
  });
}

// apps/api/src/routes/block.ts
async function registerBlockRoutes(app) {
  app.post("/users/:targetId/block", async (req, reply) => {
    const me = requireAuth(req, reply);
    if (!me) return;
    const { targetId } = req.params;
    if (targetId === me) return reply.code(400).send({ error: "You cannot block yourself" });
    await prisma.block.upsert({
      where: { blockerId_blockedId: { blockerId: me, blockedId: targetId } },
      update: {},
      create: { blockerId: me, blockedId: targetId }
    });
    await prisma.follow.deleteMany({
      where: {
        OR: [
          { followerId: me, followingId: targetId },
          { followerId: targetId, followingId: me }
        ]
      }
    });
    return { blocked: true };
  });
  app.delete("/users/:targetId/block", async (req, reply) => {
    const me = requireAuth(req, reply);
    if (!me) return;
    const { targetId } = req.params;
    await prisma.block.deleteMany({
      where: { blockerId: me, blockedId: targetId }
    });
    return { blocked: false };
  });
  app.get("/me/blocked", async (req, reply) => {
    const me = requireAuth(req, reply);
    if (!me) return;
    const blocks = await prisma.block.findMany({
      where: { blockerId: me },
      include: {
        blocked: { select: { id: true, handle: true, name: true, avatarUrl: true } }
      },
      orderBy: { createdAt: "desc" }
    });
    return { blocked: blocks.map((b) => ({ ...b.blocked, blockedAt: b.createdAt })) };
  });
  app.get("/users/:targetId/block-status", async (req, reply) => {
    const me = requireAuth(req, reply);
    if (!me) return;
    const { targetId } = req.params;
    const block = await prisma.block.findUnique({
      where: { blockerId_blockedId: { blockerId: me, blockedId: targetId } }
    });
    const reverse = await prisma.block.findUnique({
      where: { blockerId_blockedId: { blockerId: targetId, blockedId: me } }
    });
    return { blocking: !!block, blockedByThem: !!reverse };
  });
}

// apps/api/src/routes/report.ts
var VALID_REASONS = ["spam", "harassment", "hate_speech", "misinformation", "illegal", "nsfw", "other"];
var VALID_TYPES = ["post", "user", "reel", "comment"];
async function registerReportRoutes(app) {
  app.post("/report", async (req, reply) => {
    const me = requireAuth(req, reply);
    if (!me) return;
    const { targetType, targetId, reason, details } = req.body;
    if (!VALID_TYPES.includes(targetType)) {
      return reply.code(400).send({ error: `targetType must be one of: ${VALID_TYPES.join(", ")}` });
    }
    if (!VALID_REASONS.includes(reason)) {
      return reply.code(400).send({ error: `reason must be one of: ${VALID_REASONS.join(", ")}` });
    }
    if (!targetId?.trim()) return reply.code(400).send({ error: "targetId is required" });
    const existing = await prisma.report.findFirst({
      where: { reporterId: me, targetType, targetId }
    });
    if (existing) return reply.code(409).send({ error: "You have already reported this content" });
    const report = await prisma.report.create({
      data: { reporterId: me, targetType, targetId, reason, details: details?.trim() ?? null }
    });
    const count = await prisma.report.count({ where: { targetType, targetId } });
    if (count >= 5) {
      await prisma.notification.create({
        data: {
          userId: me,
          /* placeholder — sentinel processes it */
          kind: "system",
          text: `[AUTO] ${targetType} ${targetId} has ${count} reports \u2014 review needed`
        }
      }).catch(() => {
      });
    }
    return reply.code(201).send({ ok: true, reportId: report.id });
  });
  app.get("/admin/reports", async (req, reply) => {
    const me = requireAuth(req, reply);
    if (!me) return;
    const user = await prisma.user.findUnique({ where: { id: me }, select: { walletAddress: true } });
    const treasury = (process.env.TREASURY_ADDRESS ?? "").toLowerCase();
    if (user?.walletAddress?.toLowerCase() !== treasury) {
      return reply.code(403).send({ error: "Owner access only" });
    }
    const { status = "pending" } = req.query;
    const reports = await prisma.report.findMany({
      where: { status },
      orderBy: { createdAt: "desc" },
      take: 100,
      include: { reporter: { select: { handle: true, name: true } } }
    });
    return { reports };
  });
  app.patch("/admin/reports/:id", async (req, reply) => {
    const me = requireAuth(req, reply);
    if (!me) return;
    const user = await prisma.user.findUnique({ where: { id: me }, select: { walletAddress: true } });
    const treasury = (process.env.TREASURY_ADDRESS ?? "").toLowerCase();
    if (user?.walletAddress?.toLowerCase() !== treasury) {
      return reply.code(403).send({ error: "Owner access only" });
    }
    const { id } = req.params;
    const { status } = req.body;
    const valid = ["reviewed", "resolved", "dismissed"];
    if (!valid.includes(status)) return reply.code(400).send({ error: `status must be one of: ${valid.join(", ")}` });
    const updated = await prisma.report.update({ where: { id }, data: { status } });
    return { ok: true, report: updated };
  });
}

