async function registerBlogRoutes(app) {
  app.get("/blog/info", async () => {
    return {
      creationFeePartAmount: BLOG_CREATION_FEE_PART,
      maxContentLength: MAX_CONTENT_LENGTH,
      maxTitleLength: MAX_TITLE_LENGTH,
      validCategories: VALID_CATEGORIES,
      moderationPolicy: "Otomatik i\xE7erik denetimi + insan moderasyonu aktif. \u0130hlal durumunda yaz\u0131 kald\u0131r\u0131l\u0131r, \xFCcret iade edilmez."
    };
  });
  app.get("/blog", async (req) => {
    const { category, featured, limit = "20", cursor } = req.query;
    const take = Math.min(Number(limit), 50);
    try {
      const posts = await prisma.blogPost.findMany({
        where: {
          published: true,
          ...category ? { category } : {},
          ...featured === "true" ? { featured: true } : {},
          ...cursor ? { createdAt: { lt: new Date(cursor) } } : {}
        },
        orderBy: { createdAt: "desc" },
        take,
        include: { author: { select: { handle: true, name: true, avatarUrl: true, verified: true } } }
      });
      return {
        posts,
        nextCursor: posts.length === take ? posts[posts.length - 1].createdAt.toISOString() : null
      };
    } catch {
      const filtered = category ? DEMO_BLOG_POSTS.filter((p) => p.category === category) : DEMO_BLOG_POSTS;
      return { posts: cursor ? [] : filtered, nextCursor: null, demo: true };
    }
  });
  app.get("/blog/categories", async () => {
    const counts = await prisma.blogPost.groupBy({
      by: ["category"],
      where: { published: true },
      _count: { id: true },
      orderBy: { _count: { id: "desc" } }
    });
    return { categories: counts.map((c) => ({ name: c.category, count: c._count.id })) };
  });
  app.get("/blog/:slug", async (req, reply) => {
    const { slug } = req.params;
    const post = await prisma.blogPost.findUnique({
      where: { slug },
      include: { author: { select: { handle: true, name: true, avatarUrl: true, verified: true, bio: true } } }
    });
    if (!post || !post.published) return reply.code(404).send({ error: "Post not found" });
    await prisma.blogPost.update({ where: { slug }, data: { views: { increment: 1 } } });
    return post;
  });
  app.post("/blog", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const {
      title,
      content,
      excerpt,
      coverUrl,
      category,
      tags,
      hasPoll,
      pollQuestion,
      pollOptions,
      featured
    } = req.body;
    if (!title?.trim() || !content?.trim())
      return reply.code(400).send({ error: "title ve content zorunludur" });
    if (title.trim().length > MAX_TITLE_LENGTH)
      return reply.code(400).send({ error: `Ba\u015Fl\u0131k maksimum ${MAX_TITLE_LENGTH} karakter olabilir` });
    if (content.trim().length > MAX_CONTENT_LENGTH)
      return reply.code(400).send({ error: `\u0130\xE7erik maksimum ${MAX_CONTENT_LENGTH} karakter olabilir` });
    if (category && !VALID_CATEGORIES.includes(category))
      return reply.code(400).send({ error: `category \u015Funlardan biri olmal\u0131: ${VALID_CATEGORIES.join(", ")}` });
    if (hasPoll && (!pollQuestion || !pollOptions || pollOptions.length < 2))
      return reply.code(400).send({ error: "Anket i\xE7in pollQuestion ve en az 2 se\xE7enek gerekli" });
    const bannedHit = hasBannedContent(title + " " + content);
    if (bannedHit)
      return reply.code(400).send({ error: "\u0130\xE7erik politikas\u0131na ayk\u0131r\u0131 i\xE7erik tespit edildi. Yaz\u0131 yay\u0131nlanamaz." });
    const user = await prisma.user.findUnique({
      where: { id: userId },
      select: { id: true, earningsPart: true, handle: true }
    });
    if (!user) return reply.code(401).send({ error: "Kullan\u0131c\u0131 bulunamad\u0131" });
    const balance = Number(user.earningsPart ?? 0);
    if (balance < BLOG_CREATION_FEE_PART) {
      return reply.code(402).send({
        error: `Blog yaz\u0131s\u0131 olu\u015Fturmak i\xE7in ${BLOG_CREATION_FEE_PART} PART gerekmektedir. Mevcut bakiye: ${balance} PART`,
        required: BLOG_CREATION_FEE_PART,
        balance,
        shortBy: BLOG_CREATION_FEE_PART - balance
      });
    }
    const slug = title.toLowerCase().replace(/[^a-z0-9\s-]/g, "").trim().replace(/\s+/g, "-").slice(0, 80) + "-" + Date.now().toString(36);
    const [, post] = await prisma.$transaction([
      prisma.user.update({
        where: { id: userId },
        data: { earningsPart: { decrement: BLOG_CREATION_FEE_PART } }
      }),
      prisma.blogPost.create({
        data: {
          authorId: userId,
          title: title.trim(),
          slug,
          content: content.trim(),
          excerpt: excerpt?.trim(),
          coverUrl,
          category: category ?? "general",
          tags: tags ?? [],
          readingMins: estimateReadingMins(content),
          hasPoll: hasPoll ?? false,
          pollQuestion,
          pollOptions: pollOptions ?? [],
          featured: featured ?? false
        }
      })
    ]);
    return reply.code(201).send({
      ...post,
      feePaid: BLOG_CREATION_FEE_PART,
      message: `Blog yaz\u0131n\u0131z olu\u015Fturuldu! ${BLOG_CREATION_FEE_PART} PART \xFCcret kesildi.`
    });
  });
  app.post("/blog/:slug/like", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { slug } = req.params;
    const post = await prisma.blogPost.findUnique({ where: { slug } });
    if (!post) return reply.code(404).send({ error: "Not found" });
    await prisma.blogPost.update({ where: { slug }, data: { likes: { increment: 1 } } });
    return { liked: true };
  });
  app.post("/blog/:slug/report", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { slug } = req.params;
    const { reason } = req.body;
    const post = await prisma.blogPost.findUnique({ where: { slug } });
    if (!post) return reply.code(404).send({ error: "Not found" });
    await prisma.platformSetting.upsert({
      where: { key: `blog_report_${post.id}_${userId}` },
      update: { value: reason ?? "violation" },
      create: { key: `blog_report_${post.id}_${userId}`, value: reason ?? "violation" }
    });
    return { ok: true, message: "\u015Eikayetiniz al\u0131nd\u0131. Moderasyon ekibimiz inceleyecek." };
  });
}

// apps/api/src/routes/launchpad.ts
var VALID_STATUSES = ["upcoming", "active", "ended", "cancelled"];
var BLOCKED_COUNTRY_CODES = ["US", "UK", "GB", "CA", "CN"];
var LEGAL_DISCLAIMER = `Bu IDO kat\u0131l\u0131m\u0131 yat\u0131r\u0131m tavsiyesi de\u011Fildir. Kripto para yat\u0131r\u0131mlar\u0131 y\xFCksek risk i\xE7erir.
De\u011Ferin tamam\u0131n\u0131 kaybedebilirsiniz. Yaln\u0131zca kaybetmeyi g\xF6ze ald\u0131\u011F\u0131n\u0131z miktar\u0131 yat\u0131r\u0131n.
Baz\u0131 yarg\u0131 b\xF6lgelerinden kat\u0131l\u0131m yasal k\u0131s\u0131tlamalara tabidir. Kendi yarg\u0131 b\xF6lgenizin yasal gerekliliklerini kontrol edin.
Saphara Platform herhangi bir proje i\xE7in finansal garanti vermez.`;
var VESTING_TEMPLATES = {
  standard: {
    name: "Standart",
    tgeUnlockPct: 15,
    cliffMonths: 1,
    linearMonths: 9,
    desc: "TGE'de %15, 1 ay cliff, 9 ay lineer"
  },
  aggressive: {
    name: "H\u0131zl\u0131",
    tgeUnlockPct: 25,
    cliffMonths: 0,
    linearMonths: 6,
    desc: "TGE'de %25, cliff yok, 6 ay lineer"
  },
  conservative: {
    name: "Muhafazak\xE2r",
    tgeUnlockPct: 10,
    cliffMonths: 3,
    linearMonths: 12,
    desc: "TGE'de %10, 3 ay cliff, 12 ay lineer"
  }
};
var ALLOCATION_TIERS = [
  { name: "Bronz", minStake: 500, ticketWeight: 1, guaranteed: false, fcfs: true },
  { name: "G\xFCm\xFC\u015F", minStake: 2e3, ticketWeight: 4, guaranteed: false, fcfs: true },
  { name: "Alt\u0131n", minStake: 5e3, ticketWeight: 10, guaranteed: true, fcfs: false },
  { name: "Elmas", minStake: 2e4, ticketWeight: 40, guaranteed: true, fcfs: false }
];
var PLATFORM_IDO_FEE_PCT = 3;
async function registerLaunchpadRoutes(app) {
  app.get("/launchpad/info", async () => {
    return {
      platformFeePct: PLATFORM_IDO_FEE_PCT,
      blockedCountries: BLOCKED_COUNTRY_CODES,
      legalDisclaimer: LEGAL_DISCLAIMER,
      allocationTiers: ALLOCATION_TIERS,
      vestingTemplates: VESTING_TEMPLATES,
      minRaiseUsdt: 1e4,
      maxRaiseUsdt: 5e6
    };
  });
  app.get("/launchpad", async (req) => {
    const { status, limit = "20" } = req.query;
    const take = Math.min(Number(limit), 50);
    const projects = await prisma.launchpadProject.findMany({
      where: status ? { status } : void 0,
      orderBy: [{ status: "asc" }, { startAt: "asc" }],
      take,
      include: { creator: { select: { handle: true, name: true, avatarUrl: true, verified: true } } }
    });
    const enriched = projects.map((p) => ({
      ...p,
      progress: Number(p.targetAmount) > 0 ? Math.min(100, parseFloat((Number(p.raisedAmount) / Number(p.targetAmount) * 100).toFixed(1))) : 0,
      vestingInfo: getVestingDisplay(p),
      disclaimer: "Bu IDO finansal tavsiye de\u011Fildir. Yat\u0131r\u0131m kararlar\u0131n\u0131z\u0131 kendi ara\u015Ft\u0131rman\u0131za dayand\u0131r\u0131n."
    }));
    return { projects: enriched };
  });
  app.get("/launchpad/:id", async (req, reply) => {
    const { id } = req.params;
    const project = await prisma.launchpadProject.findUnique({
      where: { id },
      include: { creator: { select: { handle: true, name: true, avatarUrl: true, verified: true, bio: true } } }
    });
    if (!project) return reply.code(404).send({ error: "Project not found" });
    return {
      ...project,
      progress: Number(project.targetAmount) > 0 ? Math.min(100, parseFloat((Number(project.raisedAmount) / Number(project.targetAmount) * 100).toFixed(1))) : 0,
      vestingInfo: getVestingDisplay(project),
      allocationTiers: ALLOCATION_TIERS,
      legalDisclaimer: LEGAL_DISCLAIMER,
      platformFeePct: PLATFORM_IDO_FEE_PCT
    };
  });
  app.post("/launchpad", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const {
      name,
      symbol,
      tagline,
      description,
      logoUrl,
      bannerUrl,
      websiteUrl,
      twitterUrl,
      telegramUrl,
      whitepaperUrl,
      targetAmount,
      tokenPrice,
      totalSupply,
      minBuy,
      maxBuy,
      startAt,
      endAt,
      chain,
      tgeUnlockPct,
      cliffMonths,
      linearMonths,
      vestingTemplate
    } = req.body;
    if (!name || !symbol || !description || !targetAmount || !startAt || !endAt)
      return reply.code(400).send({ error: "name, symbol, description, targetAmount, startAt, endAt zorunludur" });
    if (symbol.length > 10)
      return reply.code(400).send({ error: "symbol maks. 10 karakter" });
    if (new Date(startAt) >= new Date(endAt))
      return reply.code(400).send({ error: "endAt, startAt'tan sonra olmal\u0131" });
    if (Number(targetAmount) < 1e4)
      return reply.code(400).send({ error: "Minimum hedef tutar 10.000 USDT e\u015Fde\u011Feridir" });
    let tge = tgeUnlockPct ?? VESTING_TEMPLATES.standard.tgeUnlockPct;
    let cliff = cliffMonths ?? VESTING_TEMPLATES.standard.cliffMonths;
    let linear = linearMonths ?? VESTING_TEMPLATES.standard.linearMonths;
    if (vestingTemplate && VESTING_TEMPLATES[vestingTemplate]) {
      const tmpl = VESTING_TEMPLATES[vestingTemplate];
      tge = tmpl.tgeUnlockPct;
      cliff = tmpl.cliffMonths;
      linear = tmpl.linearMonths;
    }
    if (tge < 5 || tge > 50) return reply.code(400).send({ error: "TGE unlock %5-%50 aras\u0131nda olmal\u0131" });
    if (cliff < 0 || cliff > 6) return reply.code(400).send({ error: "Cliff 0-6 ay aras\u0131nda olmal\u0131" });
    if (linear < 3 || linear > 24) return reply.code(400).send({ error: "Lineer vesting 3-24 ay olmal\u0131" });
    const project = await prisma.launchpadProject.create({
      data: {
        creatorId: userId,
        name: name.trim(),
        symbol: symbol.trim().toUpperCase(),
        tagline: tagline?.trim(),
        description: description.trim(),
        logoUrl,
        bannerUrl,
        websiteUrl,
        twitterUrl,
        telegramUrl,
        whitepaperUrl,
        targetAmount: targetAmount ?? 0,
        tokenPrice: tokenPrice ?? 0,
        totalSupply: totalSupply ?? 0,
        minBuy: minBuy ?? 100,
        maxBuy: maxBuy ?? 1e4,
        startAt: new Date(startAt),
        endAt: new Date(endAt),
        chain: chain ?? "BSC",
        status: new Date(startAt) > /* @__PURE__ */ new Date() ? "upcoming" : "active",
        tgeUnlockPct: tge,
        cliffMonths: cliff,
        linearMonths: linear
      }
    });
    return reply.code(201).send({
      ...project,
      vestingInfo: getVestingDisplay(project),
      legalDisclaimer: LEGAL_DISCLAIMER,
      message: "Proje olu\u015Fturuldu. Yay\u0131na al\u0131nmadan \xF6nce moderasyon ekibimiz inceleyecektir."
    });
  });
  app.post("/launchpad/:id/participate", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { id } = req.params;
    const { amount, countryCode, acceptedRisk } = req.body;
    const country = (countryCode ?? "").toUpperCase();
    if (BLOCKED_COUNTRY_CODES.includes(country)) {
      return reply.code(403).send({
        error: "Bu yarg\u0131 b\xF6lgesinden IDO kat\u0131l\u0131m\u0131 yasal k\u0131s\u0131tlamalar nedeniyle m\xFCmk\xFCn de\u011Fildir.",
        blockedCountry: country
      });
    }
    if (!acceptedRisk) {
      return reply.code(400).send({
        error: "Kat\u0131lmak i\xE7in risk uyar\u0131s\u0131n\u0131 kabul etmeniz gerekir.",
        disclaimer: LEGAL_DISCLAIMER
      });
    }
    const project = await prisma.launchpadProject.findUnique({ where: { id } });
    if (!project) return reply.code(404).send({ error: "Project not found" });
    if (project.status !== "active") return reply.code(400).send({ error: "Proje \u015Fu an aktif de\u011Fil" });
    if (amount < Number(project.minBuy) || amount > Number(project.maxBuy)) {
      return reply.code(400).send({
        error: `Tutar ${project.minBuy} - ${project.maxBuy} PART aras\u0131nda olmal\u0131`
      });
    }
    await prisma.launchpadProject.update({
      where: { id },
      data: {
        raisedAmount: { increment: amount },
        participants: { increment: 1 }
      }
    });
    return {
      ok: true,
      invested: amount,
      projectId: id,
      message: `${amount} PART yat\u0131r\u0131ld\u0131. Token da\u011F\u0131t\u0131m\u0131 vesting takviminde yap\u0131lacak.`
    };
  });
  app.post("/launchpad/:id/remind", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { id } = req.params;
    const project = await prisma.launchpadProject.findUnique({ where: { id } });
    if (!project) return reply.code(404).send({ error: "Project not found" });
    const key = `launchpad_remind_${id}`;
    const rec = await prisma.platformSetting.findUnique({ where: { key } });
    let list = [];
    if (rec) {
      try {
        list = JSON.parse(rec.value);
      } catch {
        list = [];
      }
    }
    if (!list.includes(userId)) {
      list.push(userId);
      await prisma.platformSetting.upsert({
        where: { key },
        update: { value: JSON.stringify(list) },
        create: { key, value: JSON.stringify(list) }
      });
    }
    return { ok: true, reminded: true, total: list.length };
  });
  app.patch("/launchpad/:id/status", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { id } = req.params;
    const { status } = req.body;
    if (!VALID_STATUSES.includes(status))
      return reply.code(400).send({ error: `status \u015Funlardan biri olmal\u0131: ${VALID_STATUSES.join(", ")}` });
    const project = await prisma.launchpadProject.findUnique({ where: { id } });
    if (!project) return reply.code(404).send({ error: "Not found" });
    if (project.creatorId !== userId) return reply.code(403).send({ error: "Proje sahibi de\u011Filsiniz" });
    const updated = await prisma.launchpadProject.update({ where: { id }, data: { status } });
    return { ok: true, project: updated };
  });
}
function getVestingDisplay(project) {
  const tge = project.tgeUnlockPct ?? VESTING_TEMPLATES.standard.tgeUnlockPct;
  const cliff = project.cliffMonths ?? VESTING_TEMPLATES.standard.cliffMonths;
  const linear = project.linearMonths ?? VESTING_TEMPLATES.standard.linearMonths;
  const steps = [];
  steps.push(`TGE'de %${tge} an\u0131nda serbest b\u0131rak\u0131l\u0131r`);
  if (cliff > 0) steps.push(`${cliff} ay cliff (bekletme s\xFCresi)`);
  steps.push(`Kalan %${100 - tge}, ${linear} ayda e\u015Fit miktarlarda serbest b\u0131rak\u0131l\u0131r`);
  return { tgeUnlockPct: tge, cliffMonths: cliff, linearMonths: linear, steps };
}

// apps/api/src/routes/nft.ts
var PLATFORM_COMMISSION = 0.025;
var DEFAULT_ROYALTY = 0.05;
var MIN_ROYALTY = 0.025;
var MAX_ROYALTY = 0.1;
var MINT_FEE_FIXED_PART = 5;
var AUDIT_INFO = {
  auditor: "CertiK",
  status: "pending",
  expected: "Q3 2025",
  contractStandards: ["ERC-721", "ERC-2981 (Royalties)"],
  royaltySupport: "On-chain ERC-2981 royalty enforced at marketplace level"
};
var RARITY_WEIGHTS = [
  { rarity: "legendary", weight: 1 },
  { rarity: "epic", weight: 4 },
  { rarity: "rare", weight: 15 },
  { rarity: "uncommon", weight: 30 },
  { rarity: "common", weight: 50 }
];
function rollRarity() {
  const roll = Math.random() * 100;
  let cumulative = 0;
  for (const r of RARITY_WEIGHTS) {
    cumulative += r.weight;
    if (roll <= cumulative) return r.rarity;
  }
  return "common";
}
function generateAttributes(rarity) {
  const backgrounds = ["Cosmic", "Forest", "Ocean", "Desert", "Neon", "Void", "Aurora"];
  const eyes = ["Laser", "Diamond", "Normal", "Sleepy", "Wild", "Closed", "Glowing"];
  const accessories = ["Crown", "Glasses", "Hat", "None", "Chain", "Earring", "Mask"];
  const pick = (arr) => arr[Math.floor(Math.random() * arr.length)];
  return [
    { trait_type: "Background", value: pick(backgrounds) },
    { trait_type: "Eyes", value: pick(eyes) },
    { trait_type: "Accessory", value: pick(accessories) },
    { trait_type: "Rarity", value: rarity }
  ];
}
async function registerNftRoutes(app) {
  app.get("/nft/info", async () => {
    return {
      platformCommissionPct: PLATFORM_COMMISSION * 100,
      defaultRoyaltyPct: DEFAULT_ROYALTY * 100,
      minRoyaltyPct: MIN_ROYALTY * 100,
      maxRoyaltyPct: MAX_ROYALTY * 100,
      mintFeeFixedPart: MINT_FEE_FIXED_PART,
      mintFeeWhitelistPart: MINT_FEE_FIXED_PART / 2,
      royaltyStandard: "ERC-2981",
      auditInfo: AUDIT_INFO,
      feeBreakdown: {
        example: "1000 PART sat\u0131\u015Fta: %5 royalty (50 PART yarat\u0131c\u0131), %2.5 platform (23.75 PART), sat\u0131c\u0131 926.25 PART al\u0131r"
      }
    };
  });
  app.get("/nft/collections", async (req) => {
    const { status } = req.query;
    const collections = await prisma.nftCollection.findMany({
      where: status ? { status } : void 0,
      orderBy: { createdAt: "desc" },
      include: {
        creator: { select: { handle: true, name: true, avatarUrl: true, verified: true } },
        _count: { select: { tokens: true, whitelist: true } }
      }
    });
    return { collections };
  });
  app.get("/nft/collections/:id", async (req, reply) => {
    const { id } = req.params;
    const col = await prisma.nftCollection.findUnique({
      where: { id },
      include: {
        creator: { select: { handle: true, name: true, avatarUrl: true, verified: true } },
        _count: { select: { tokens: true, whitelist: true } }
      }
    });
    if (!col) return reply.code(404).send({ error: "Collection not found" });
    return col;
  });
  app.get("/nft/collections/:id/tokens", async (req) => {
    const { id } = req.params;
    const { limit = "24", offset = "0", listed } = req.query;
    const tokens = await prisma.nftToken.findMany({
      where: {
        collectionId: id,
        ...listed === "true" ? { listed: true } : {}
      },
      orderBy: { mintedAt: "desc" },
      take: Math.min(Number(limit), 100),
      skip: Number(offset),
      include: { owner: { select: { handle: true, name: true, avatarUrl: true } } }
    });
    return { tokens };
  });
  app.get("/nft/collections/:id/whitelist", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { id } = req.params;
    const entry = await prisma.nftWhitelist.findUnique({
      where: { collectionId_userId: { collectionId: id, userId } }
    });
    return {
      whitelisted: !!entry,
      slots: entry?.slots ?? 0,
      used: entry?.used ?? 0,
      remaining: entry ? entry.slots - entry.used : 0
    };
  });
  app.post("/nft/collections/:id/whitelist/apply", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { id } = req.params;
    const col = await prisma.nftCollection.findUnique({ where: { id } });
    if (!col) return reply.code(404).send({ error: "Collection not found" });
    if (col.status === "ended" || col.status === "soldout")
      return reply.code(400).send({ error: "Collection is no longer accepting whitelist applications" });
    const existing = await prisma.nftWhitelist.findUnique({
      where: { collectionId_userId: { collectionId: id, userId } }
    });
    if (existing) return reply.code(409).send({ error: "Already on whitelist", entry: existing });
    const entry = await prisma.nftWhitelist.create({
      data: { collectionId: id, userId, slots: 2, source: "application" }
    });
    return reply.code(201).send({ ok: true, entry, message: "Whitelist ba\u015Fvurunuz al\u0131nd\u0131! 2 mint hakk\u0131 kazand\u0131n\u0131z." });
  });
  app.post("/nft/collections/:id/mint", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { id } = req.params;
    const { quantity = 1, useWhitelist = false } = req.body;
    if (quantity < 1 || quantity > 5) return reply.code(400).send({ error: "Mint miktar\u0131 1-5 aras\u0131nda olmal\u0131" });
    const col = await prisma.nftCollection.findUnique({ where: { id } });
    if (!col) return reply.code(404).send({ error: "Collection not found" });
    if (col.status !== "active") return reply.code(400).send({ error: "Mint \u015Fu an aktif de\u011Fil" });
    if (col.minted + quantity > col.maxSupply) {
      return reply.code(400).send({ error: `Yaln\u0131zca ${col.maxSupply - col.minted} token kald\u0131` });
    }
    const alreadyMinted = await prisma.nftToken.count({ where: { collectionId: id, minterId: userId } });
    if (alreadyMinted + quantity > col.maxPerWallet) {
      return reply.code(400).send({ error: `C\xFCzdan ba\u015F\u0131na maksimum ${col.maxPerWallet} mint hakk\u0131` });
    }
    let pricePerToken = Number(col.mintPrice);
    if (useWhitelist) {
      const wl = await prisma.nftWhitelist.findUnique({
        where: { collectionId_userId: { collectionId: id, userId } }
      });
      if (!wl || wl.used + quantity > wl.slots)
        return reply.code(403).send({ error: "Whitelist hakk\u0131n\u0131z yetersiz" });
      pricePerToken = Number(col.whitelistPrice ?? col.mintPrice);
      await prisma.nftWhitelist.update({
        where: { collectionId_userId: { collectionId: id, userId } },
        data: { used: { increment: quantity } }
      });
    }
    const platformFee = (useWhitelist ? MINT_FEE_FIXED_PART / 2 : MINT_FEE_FIXED_PART) * quantity;
    const totalCost = pricePerToken * quantity + platformFee;
    const startId = col.minted + 1;
    const tokens = await prisma.$transaction(
      Array.from({ length: quantity }, (_, i) => {
        const tokenId = startId + i;
        const rarity = rollRarity();
        const styles = ["bottts", "adventurer", "lorelei", "bottts-neutral"];
        const style = styles[tokenId % styles.length];
        const imageUrl2 = `https://api.dicebear.com/9.x/${style}/svg?seed=${col.symbol}-${tokenId}&size=200`;
        return prisma.nftToken.create({
          data: {
            tokenId,
            collectionId: id,
            ownerId: userId,
            minterId: userId,
            name: `${col.name} #${tokenId}`,
            description: `${col.name} koleksiyonundan #${tokenId} numaral\u0131 token`,
            imageUrl: imageUrl2,
            rarity,
            attributes: generateAttributes(rarity)
          }
        });
      })
    );
    await prisma.nftCollection.update({
      where: { id },
      data: {
        minted: { increment: quantity },
        status: col.minted + quantity >= col.maxSupply ? "soldout" : col.status
      }
    });
    return reply.code(201).send({
      ok: true,
      tokens,
      pricePerToken,
      platformFee,
      totalCost,
      message: `${quantity} NFT ba\u015Far\u0131yla mint edildi! Toplam: ${totalCost} PART (${platformFee} PART platform bedeli dahil)`
    });
  });
  app.get("/nft/my", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const tokens = await prisma.nftToken.findMany({
      where: { ownerId: userId },
      orderBy: { mintedAt: "desc" },
      include: { collection: { select: { id: true, name: true, symbol: true, royaltyPct: true } } }
    });
    return { tokens };
  });
  app.post("/nft/tokens/:tokenId/list", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { tokenId } = req.params;
    const { price } = req.body;
    if (!price || price <= 0) return reply.code(400).send({ error: "Ge\xE7erli fiyat girin" });
    const token = await prisma.nftToken.findUnique({ where: { id: tokenId } });
    if (!token) return reply.code(404).send({ error: "Token bulunamad\u0131" });
    if (token.ownerId !== userId) return reply.code(403).send({ error: "Bu NFT size ait de\u011Fil" });
    const listing = await prisma.listing.create({
      data: {
        sellerId: userId,
        title: token.name,
        description: `${token.name} \u2014 Rarity: ${token.rarity}`,
        imageUrl: token.imageUrl,
        pricePart: price,
        category: "nft",
        commissionPct: 2.5,
        nftTokenId: tokenId
      }
    });
    await prisma.nftToken.update({ where: { id: tokenId }, data: { listed: true, listingPrice: price } });
    return reply.code(201).send({ ok: true, listing });
  });
  app.delete("/nft/tokens/:tokenId/list", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { tokenId } = req.params;
    const token = await prisma.nftToken.findUnique({ where: { id: tokenId } });
    if (!token || token.ownerId !== userId) return reply.code(403).send({ error: "Yetki yok" });
    await prisma.$transaction([
      prisma.nftToken.update({ where: { id: tokenId }, data: { listed: false, listingPrice: null } }),
      prisma.listing.deleteMany({ where: { nftTokenId: tokenId, sellerId: userId, status: "Listed" } })
    ]);
    return { ok: true };
  });
  app.get("/nft/marketplace", async (req) => {
    const { limit = "24", rarity, collection } = req.query;
    const tokens = await prisma.nftToken.findMany({
      where: {
        listed: true,
        ...rarity ? { rarity } : {},
        ...collection ? { collectionId: collection } : {}
      },
      orderBy: { listingPrice: "asc" },
      take: Math.min(Number(limit), 100),
      include: {
        owner: { select: { handle: true, name: true, avatarUrl: true } },
        collection: { select: { id: true, name: true, symbol: true, royaltyPct: true } }
      }
    });
    return { tokens };
  });
  app.post("/nft/tokens/:tokenId/buy", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { tokenId } = req.params;
    const token = await prisma.nftToken.findUnique({
      where: { id: tokenId },
      include: { collection: true }
    });
    if (!token) return reply.code(404).send({ error: "Token bulunamad\u0131" });
    if (!token.listed) return reply.code(400).send({ error: "Bu NFT sat\u0131\u015Fta de\u011Fil" });
    if (token.ownerId === userId) return reply.code(400).send({ error: "Kendi NFT'nizi sat\u0131n alamazs\u0131n\u0131z" });
    const price = Number(token.listingPrice ?? 0);
    const rawRoyaltyPct = Number(token.collection?.royaltyPct ?? 0) / 100;
    const royaltyPct = Math.min(MAX_ROYALTY, Math.max(MIN_ROYALTY, rawRoyaltyPct || DEFAULT_ROYALTY));
    const royaltyAmount = Math.round(price * royaltyPct * 100) / 100;
    const platformFee = Math.round((price - royaltyAmount) * PLATFORM_COMMISSION * 100) / 100;
    const sellerReceives = Math.round((price - royaltyAmount - platformFee) * 100) / 100;
    const creatorId = token.collection?.creatorId;
    await prisma.$transaction([
      prisma.nftToken.update({
        where: { id: tokenId },
        data: { ownerId: userId, listed: false, listingPrice: null, soldAt: /* @__PURE__ */ new Date(), salePrice: price }
      }),
      prisma.listing.updateMany({
        where: { nftTokenId: tokenId, status: "Listed" },
        data: { status: "Completed", buyerAddress: userId, soldAt: /* @__PURE__ */ new Date() }
      }),
      prisma.user.update({ where: { id: token.ownerId }, data: { earningsPart: { increment: sellerReceives } } }),
      ...creatorId && creatorId !== token.ownerId ? [prisma.user.update({ where: { id: creatorId }, data: { earningsPart: { increment: royaltyAmount } } })] : []
    ]);
    return {
      ok: true,
      price,
      royaltyAmount,
      royaltyPct: Math.round(royaltyPct * 1e3) / 10,
      platformFee,
      sellerReceives,
      message: `NFT sat\u0131n al\u0131nd\u0131! ${price} PART \xF6dendi. Yarat\u0131c\u0131 royalty: ${royaltyAmount} PART, platform: ${platformFee} PART`
    };
  });
}

// apps/api/src/routes/dao.ts
async function registerDaoRoutes(app) {
  app.get("/dao/proposals", async (req) => {
    const { status, type, limit = "20", offset = "0" } = req.query;
    const proposals = await prisma.daoProposal.findMany({
      where: {
        ...status ? { status } : {},
        ...type ? { type } : {}
      },
      orderBy: { createdAt: "desc" },
      take: Math.min(Number(limit), 50),
      skip: Number(offset),
      include: {
        author: { select: { handle: true, name: true, avatarUrl: true, verified: true } },
        _count: { select: { votes: true } }
      }
    });
    return { proposals };
  });
  app.get("/dao/proposals/:id", async (req, reply) => {
    const { id } = req.params;
    const proposal = await prisma.daoProposal.findUnique({
      where: { id },
      include: {
        author: { select: { handle: true, name: true, avatarUrl: true, verified: true } },
        votes: {
          orderBy: { votePower: "desc" },
          take: 50,
          include: { voter: { select: { handle: true, name: true, avatarUrl: true } } }
        },
        _count: { select: { votes: true } }
      }
    });
    if (!proposal) return reply.code(404).send({ error: "Proposal not found" });
    const totalPower = proposal.votes.reduce((a, v) => a + v.votePower, 0) || 1;
    const forPct = Math.round(proposal.votesFor / totalPower * 100);
    const agPct = Math.round(proposal.votesAgainst / totalPower * 100);
    const absPct = Math.round(proposal.votesAbstain / totalPower * 100);
    return { ...proposal, forPct, agPct, absPct };
  });
  app.post("/dao/proposals", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const {
      title,
      description,
      type = "general",
      endsAt,
      treasuryAmount,
      treasuryRecipient,
      tags = []
    } = req.body;
    if (!title?.trim()) return reply.code(400).send({ error: "Ba\u015Fl\u0131k gerekli" });
    if (!description?.trim()) return reply.code(400).send({ error: "A\xE7\u0131klama gerekli" });
    if (!endsAt) return reply.code(400).send({ error: "Biti\u015F tarihi gerekli" });
    const endsAtDate = new Date(endsAt);
    if (endsAtDate <= /* @__PURE__ */ new Date()) return reply.code(400).send({ error: "Biti\u015F tarihi gelecekte olmal\u0131" });
    const proposal = await prisma.daoProposal.create({
      data: {
        authorId: userId,
        title: title.trim(),
        description: description.trim(),
        type,
        endsAt: endsAtDate,
        treasuryAmount: treasuryAmount ?? 0,
        treasuryRecipient,
        tags
      },
      include: { author: { select: { handle: true, name: true, avatarUrl: true } } }
    });
    return reply.code(201).send({ ok: true, proposal });
  });
  app.post("/dao/proposals/:id/vote", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { id } = req.params;
    const { vote, reason } = req.body;
    if (!["for", "against", "abstain"].includes(vote))
      return reply.code(400).send({ error: "Ge\xE7erli oy: for | against | abstain" });
    const proposal = await prisma.daoProposal.findUnique({ where: { id } });
    if (!proposal) return reply.code(404).send({ error: "Teklif bulunamad\u0131" });
    if (proposal.status !== "active") return reply.code(400).send({ error: "Oylama aktif de\u011Fil" });
    if (/* @__PURE__ */ new Date() > proposal.endsAt) return reply.code(400).send({ error: "Oylama s\xFCresi doldu" });
    const existing = await prisma.daoVote.findUnique({
      where: { proposalId_voterId: { proposalId: id, voterId: userId } }
    });
    if (existing) return reply.code(409).send({ error: "Zaten oy kulland\u0131n\u0131z" });
    const user = await prisma.user.findUnique({ where: { id: userId }, select: { earningsPart: true } });
    const balance = Number(user?.earningsPart ?? 0);
    const votePower = Math.min(100, Math.max(1, Math.floor(balance / 100)));
    const daoVote = await prisma.daoVote.create({
      data: { proposalId: id, voterId: userId, vote, votePower, reason }
    });
    await prisma.daoProposal.update({
      where: { id },
      data: {
        votesFor: vote === "for" ? { increment: votePower } : void 0,
        votesAgainst: vote === "against" ? { increment: votePower } : void 0,
        votesAbstain: vote === "abstain" ? { increment: votePower } : void 0
      }
    });
    const updated = await prisma.daoProposal.findUnique({ where: { id } });
    if (updated && /* @__PURE__ */ new Date() >= updated.endsAt) {
      const total = updated.votesFor + updated.votesAgainst + updated.votesAbstain;
      const forRatio = total > 0 ? updated.votesFor / total * 100 : 0;
      const newStatus = forRatio >= updated.passThreshold ? "passed" : "rejected";
      await prisma.daoProposal.update({ where: { id }, data: { status: newStatus } });
    }
    return reply.code(201).send({ ok: true, daoVote, votePower });
  });
  app.get("/dao/proposals/:id/my-vote", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { id } = req.params;
    const daoVote = await prisma.daoVote.findUnique({
      where: { proposalId_voterId: { proposalId: id, voterId: userId } }
    });
    return { voted: !!daoVote, vote: daoVote ?? null };
  });
  app.get("/dao/stats", async () => {
    const [total, active, passed, rejected, totalVotes] = await Promise.all([
      prisma.daoProposal.count(),
      prisma.daoProposal.count({ where: { status: "active" } }),
      prisma.daoProposal.count({ where: { status: "passed" } }),
      prisma.daoProposal.count({ where: { status: "rejected" } }),
      prisma.daoVote.count()
    ]);
    return { total, active, passed, rejected, totalVotes };
  });
  app.post("/dao/finalize", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const expired = await prisma.daoProposal.findMany({
      where: { status: "active", endsAt: { lte: /* @__PURE__ */ new Date() } }
    });
    let finalized = 0;
    for (const p of expired) {
      const total = p.votesFor + p.votesAgainst + p.votesAbstain;
      const forRatio = total > 0 ? p.votesFor / total * 100 : 0;
      const newStatus = forRatio >= p.passThreshold ? "passed" : "rejected";
      await prisma.daoProposal.update({ where: { id: p.id }, data: { status: newStatus } });
      finalized++;
    }
    return { ok: true, finalized };
  });
}

// apps/api/src/routes/referral.ts
var REFERRAL_REWARD_PART = 50;
async function registerReferralRoutes(app) {
  app.get("/referral/my", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    let stats = await prisma.userStats.findUnique({ where: { userId } });
    if (!stats) {
      stats = await prisma.userStats.create({
        data: {
          userId,
          referralCode: `REF-${userId.slice(-8).toUpperCase()}`
        }
      });
    }
    const referrals = await prisma.referralEntry.findMany({
      where: { referrerId: userId },
      orderBy: { createdAt: "desc" },
      include: { referred: { select: { handle: true, name: true, avatarUrl: true, createdAt: true } } }
    });
    const totalEarned = referrals.filter((r) => r.paid).reduce((s, r) => s + Number(r.rewardPart), 0);
    const pendingEarnings = referrals.filter((r) => !r.paid).reduce((s, r) => s + Number(r.rewardPart), 0);
    return {
      referralCode: stats.referralCode,
      referralUrl: `https://saphara.io/join?ref=${stats.referralCode}`,
      totalReferrals: referrals.length,
      paidReferrals: referrals.filter((r) => r.paid).length,
      totalEarned,
      pendingEarnings,
      referrals
    };
  });
  app.post("/referral/apply", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { referralCode } = req.body;
    if (!referralCode?.trim()) return reply.code(400).send({ error: "Referral kodu gerekli" });
    const existing = await prisma.referralEntry.findUnique({ where: { referredId: userId } });
    if (existing) return reply.code(409).send({ error: "Zaten bir referral kodunuz var" });
    const referrerStats = await prisma.userStats.findUnique({
      where: { referralCode: referralCode.trim().toUpperCase() }
    });
    if (!referrerStats) return reply.code(404).send({ error: "Ge\xE7ersiz referral kodu" });
    if (referrerStats.userId === userId) return reply.code(400).send({ error: "Kendi kodunuzu kullanamazs\u0131n\u0131z" });
    const entry = await prisma.referralEntry.create({
      data: {
        referrerId: referrerStats.userId,
        referredId: userId,
        rewardPart: REFERRAL_REWARD_PART,
        source: referralCode
      }
    });
    return reply.code(201).send({ ok: true, entry, reward: `${REFERRAL_REWARD_PART} PART \xF6d\xFCl beklemede` });
  });
  app.post("/referral/claim", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const unpaid = await prisma.referralEntry.findMany({
      where: { referrerId: userId, paid: false }
    });
    if (unpaid.length === 0) return reply.code(400).send({ error: "Bekleyen \xF6d\xFCl yok" });
    const totalReward = unpaid.reduce((s, r) => s + Number(r.rewardPart), 0);
    await prisma.$transaction([
      prisma.referralEntry.updateMany({
        where: { referrerId: userId, paid: false },
        data: { paid: true, paidAt: /* @__PURE__ */ new Date() }
      }),
      prisma.user.update({
        where: { id: userId },
        data: { earningsPart: { increment: totalReward } }
      })
    ]);
    return { ok: true, claimed: unpaid.length, totalReward, message: `${totalReward} PART \xF6d\xFCl\xFCn\xFCz hesab\u0131n\u0131za eklendi!` };
  });
  app.get("/referral/leaderboard", async () => {
    const topReferrers = await prisma.referralEntry.groupBy({
      by: ["referrerId"],
      _count: { referrerId: true },
      _sum: { rewardPart: true },
      orderBy: { _count: { referrerId: "desc" } },
      take: 20
    });
    const userIds = topReferrers.map((r) => r.referrerId);
    const users = await prisma.user.findMany({
      where: { id: { in: userIds } },
      select: { id: true, handle: true, name: true, avatarUrl: true, verified: true }
    });
    const leaderboard = topReferrers.map((r, i) => {
      const user = users.find((u) => u.id === r.referrerId);
      return {
        rank: i + 1,
        user,
        referralCount: r._count.referrerId,
        totalEarned: Number(r._sum.rewardPart ?? 0)
      };
    });
    return { leaderboard };
  });
  app.get("/referral/stats", async () => {
    const [total, paid, totalPart] = await Promise.all([
      prisma.referralEntry.count(),
      prisma.referralEntry.count({ where: { paid: true } }),
      prisma.referralEntry.aggregate({ _sum: { rewardPart: true }, where: { paid: true } })
    ]);
    return {
      totalReferrals: total,
      paidReferrals: paid,
      totalPartDistributed: Number(totalPart._sum.rewardPart ?? 0),
      rewardPerReferral: REFERRAL_REWARD_PART
    };
  });
}

